        'cities.malaga.desc'  => [ 'es'=>'Una ciudad en plena transformación, con un entorno urbano que crece en servicios y calidad de vida.','en'=>'A city in full transformation, with an urban environment growing in services and quality of life.','fr'=>'Une ville en pleine transformation, avec un environnement urbain qui grandit en services et qualité de vie.','de'=>'Eine Stadt im vollen Wandel, mit einem städtischen Umfeld, das an Dienstleistungen und Lebensqualität wächst.','ru'=>'Город в полном преобразовании, с городской средой, развивающейся в плане услуг и качества жизни.' ],
        'cities.marbella.desc'=> [ 'es'=>'Una de las zonas más exclusivas de España, con una demanda sostenida y un entorno residencial de alto nivel.','en'=>'One of the most exclusive areas in Spain, with sustained demand and a high-end residential environment.','fr'=>'L\'une des zones les plus exclusives d\'Espagne, avec une demande soutenue et un environnement résidentiel haut de gamme.','de'=>'Eine der exklusivsten Zonen Spaniens, mit anhaltender Nachfrage und einem gehobenen Wohnumfeld.','ru'=>'Один из самых эксклюзивных районов Испании, с устойчивым спросом и жилой средой высокого уровня.' ],
