        'presup.sel.recommended' => [ 'es'=>'Recomendado','en'=>'Recommended','fr'=>'Recommandé','de'=>'Empfohlen','ru'=>'Рекомендуется' ],
        'presup.sel.title'    => [ 'es'=>'¿Cuál describe mejor su situación?','en'=>'Which best describes your situation?','fr'=>'Laquelle décrit le mieux votre situation ?','de'=>'Welche beschreibt Ihre Situation am besten?','ru'=>'Что лучше всего описывает вашу ситуацию?' ],
        'presup.b.btn'        => [ 'es'=>'Quiero este análisis','en'=>'I want this analysis','fr'=>'Je veux cette analyse','de'=>'Ich möchte diese Analyse','ru'=>'Хочу этот анализ' ],
        'cont.direct.badge'   => [ 'es'=>'CONTACTO DIRECTO','en'=>'DIRECT CONTACT','fr'=>'CONTACT DIRECT','de'=>'DIREKTKONTAKT','ru'=>'ПРЯМОЙ КОНТАКТ' ],
        'cont.direct.title'   => [ 'es'=>'¿Prefiere hablar con nosotros?','en'=>'Would you prefer to speak with us?','fr'=>'Préférez-vous nous parler ?','de'=>'Möchten Sie lieber mit uns sprechen?','ru'=>'Предпочитаете поговорить с нами?' ],
        'cont.direct.sub'     => [ 'es'=>'Si su situación es diferente a las descritas o simplemente desea hablar con nuestro equipo antes de dar cualquier paso, escríbanos. Le respondemos en un plazo de 24-48 horas laborables.','en'=>'If your situation differs from those described, or you simply wish to speak with our team before taking any step, write to us. We respond within 24-48 working hours.','fr'=>'Si votre situation est différente de celles décrites ou si vous souhaitez simplement parler à notre équipe avant de faire quoi que ce soit, écrivez-nous. Nous répondons sous un délai de 24-48 heures ouvrables.','de'=>'Wenn Ihre Situation von den beschriebenen abweicht oder Sie einfach mit unserem Team sprechen möchten, bevor Sie einen Schritt unternehmen, schreiben Sie uns. Wir antworten innerhalb von 24-48 Werkstunden.','ru'=>'Если ваша ситуация отличается от описанных, или вы просто хотите поговорить с нашей командой перед любым шагом, напишите нам. Мы ответим в течение 24-48 рабочих часов.' ],
        'cont.micro'          => [ 'es'=>'Sin llamadas comerciales. Solo le contactamos para enviarle su presupuesto.','en'=>'No sales calls. We only contact you to send your quote.','fr'=>'Pas d\'appels commerciaux. Nous vous contactons uniquement pour vous envoyer votre devis.','de'=>'Keine Verkaufsanrufe. Wir kontaktieren Sie nur, um Ihr Angebot zu senden.','ru'=>'Без коммерческих звонков. Свяжемся только чтобы отправить ваше предложение.' ],
        'cont.confirm.title'  => [ 'es'=>'Mensaje recibido','en'=>'Message received','fr'=>'Message reçu','de'=>'Nachricht erhalten','ru'=>'Сообщение получено' ],
        'cont.confirm.sub'    => [ 'es'=>'Le responderemos en un plazo de 24-48 horas laborables con su presupuesto personalizado. Gracias por confiar en ROMVILL.','en'=>'We will respond within 24-48 working hours with your personalised quote. Thank you for trusting ROMVILL.','fr'=>'Nous vous répondrons sous un délai de 24-48 heures ouvrables avec votre devis personnalisé. Merci de faire confiance à ROMVILL.','de'=>'Wir antworten innerhalb von 24-48 Werkstunden mit Ihrem personalisierten Angebot. Danke, dass Sie ROMVILL vertrauen.','ru'=>'Мы ответим в течение 24-48 рабочих часов с вашим персонализированным предложением. Спасибо, что доверяете ROMVILL.' ],
        'cont.why.badge'      => [ 'es'=>'POR QUÉ ELEGIRNOS','en'=>'WHY CHOOSE US','fr'=>'POURQUOI NOUS CHOISIR','de'=>'WARUM UNS WÄHLEN','ru'=>'ПОЧЕМУ ВЫБИРАЮТ НАС' ],
        'cont.why.new.title'  => [ 'es'=>'Lo que nos diferencia.','en'=>'What sets us apart.','fr'=>'Ce qui nous distingue.','de'=>'Was uns auszeichnet.','ru'=>'Что нас отличает.' ],
        'presup.badge'        => [ 'es'=>'SOLICITAR PRESUPUESTO','en'=>'REQUEST A QUOTE','fr'=>'DEMANDER UN DEVIS','de'=>'ANGEBOT ANFORDERN','ru'=>'ЗАПРОСИТЬ ПРЕДЛОЖЕНИЕ' ],
        'presup.title'        => [ 'es'=>'Seleccione su perfil.','en'=>'Select your profile.','fr'=>'Sélectionnez votre profil.','de'=>'Wählen Sie Ihr Profil.','ru'=>'Выберите ваш профиль.' ],
        'presup.subtitle'     => [ 'es'=>'Seleccione el perfil que mejor describe su situación. A partir de ahí elaboraremos un presupuesto adaptado exclusivamente a sus necesidades.','en'=>'Select the profile that best describes your situation. From there, we will prepare a quote tailored exclusively to your needs.','fr'=>'Sélectionnez le profil qui décrit le mieux votre situation. À partir de là, nous élaborerons un devis adapté exclusivement à vos besoins.','de'=>'Wählen Sie das Profil, das Ihre Situation am besten beschreibt. Darauf aufbauend erstellen wir ein ausschließlich auf Ihre Bedürfnisse zugeschnittenes Angebot.','ru'=>'Выберите профиль, который лучше всего описывает вашу ситуацию. На его основе мы подготовим предложение, адаптированное исключительно к вашим потребностям.' ],
        'presup.btn'          => [ 'es'=>'Este es mi perfil','en'=>'This is my profile','fr'=>'C\'est mon profil','de'=>'Das ist mein Profil','ru'=>'Это мой профиль' ],
        'presup.contact.text' => [ 'es'=>'¿Prefiere contactar directamente con nuestro equipo? Si considera que su situación es diferente a las descritas anteriormente o simplemente desea hablar con nosotros antes de dar cualquier paso, estamos a su disposición.','en'=>'Would you prefer to contact our team directly? If you feel your situation differs from those described above, or simply wish to speak with us before taking any step, we are at your disposal.','fr'=>'Préférez-vous contacter directement notre équipe ? Si vous estimez que votre situation est différente de celles décrites ci-dessus, ou souhaitez simplement nous parler avant de franchir une étape, nous sommes à votre disposition.','de'=>'Möchten Sie lieber direkt mit unserem Team Kontakt aufnehmen? Falls Ihre Situation von den oben beschriebenen abweicht oder Sie einfach mit uns sprechen möchten, bevor Sie einen Schritt unternehmen, stehen wir Ihnen zur Verfügung.','ru'=>'Предпочитаете связаться с нашей командой напрямую? Если ваша ситуация отличается от описанных выше или вы просто хотите поговорить с нами перед тем, как сделать какой-либо шаг, — мы к вашим услугам.' ],
        'presup.contact.btn'  => [ 'es'=>'Contacto','en'=>'Contact','fr'=>'Contact','de'=>'Kontakt','ru'=>'Контакт' ],
        'presup.b1.title'     => [ 'es'=>'Particulares','en'=>'Private Individuals','fr'=>'Particuliers','de'=>'Privatpersonen','ru'=>'Частные лица' ],
        'presup.b1.sub'       => [ 'es'=>'Para quienes desean mudarse, instalarse o conocer una zona antes de tomar una decisión personal.','en'=>'For those who wish to relocate, settle or get to know an area before making a personal decision.','fr'=>'Pour ceux qui souhaitent déménager, s\'installer ou connaître une zone avant de prendre une décision personnelle.','de'=>'Für diejenigen, die umziehen, sich niederlassen oder eine Zone kennenlernen möchten, bevor sie eine persönliche Entscheidung treffen.','ru'=>'Для тех, кто хочет переехать, обосноваться или познакомиться с районом перед принятием личного решения.' ],
        'presup.b1.desc'      => [ 'es'=>'Familias que buscan su nuevo hogar · Residentes europeos que se instalan en España · Personas que se trasladan por motivos personales o profesionales · Padres que quieren conocer la zona donde estudia o vive un familiar','en'=>'Families looking for their new home · European residents settling in Spain · People relocating for personal or professional reasons · Parents who want to know the area where a family member studies or lives','fr'=>'Familles à la recherche de leur nouveau domicile · Résidents européens qui s\'installent en Espagne · Personnes qui déménagent pour des raisons personnelles ou professionnelles · Parents qui veulent connaître la zone où étudie ou vit un membre de la famille','de'=>'Familien, die ihr neues Zuhause suchen · Europäische Bewohner, die sich in Spanien niederlassen · Personen, die aus persönlichen oder beruflichen Gründen umziehen · Eltern, die die Zone kennenlernen möchten, wo ein Familienmitglied studiert oder lebt','ru'=>'Семьи в поисках нового дома · Европейские жители, обосновывающиеся в Испании · Люди, переезжающие по личным или профессиональным причинам · Родители, желающие узнать район, где учится или живёт член семьи' ],
        'presup.b1.time'      => [ 'es'=>'Aproximadamente 4 minutos','en'=>'Approximately 4 minutes','fr'=>'Environ 4 minutes','de'=>'Etwa 4 Minuten','ru'=>'Примерно 4 минуты' ],
        'presup.b2.title'     => [ 'es'=>'Inversores','en'=>'Investors','fr'=>'Investisseurs','de'=>'Investoren','ru'=>'Инвесторы' ],
        'presup.b2.sub'       => [ 'es'=>'Para quienes evalúan una compra, adquisición o inversión inmobiliaria en la zona.','en'=>'For those evaluating a purchase, acquisition or real estate investment in the area.','fr'=>'Pour ceux qui évaluent un achat, une acquisition ou un investissement immobilier dans la zone.','de'=>'Für diejenigen, die einen Kauf, eine Akquisition oder eine Immobilieninvestition in der Zone prüfen.','ru'=>'Для тех, кто оценивает покупку, приобретение или инвестиции в недвижимость в данном районе.' ],
        'presup.b2.desc'      => [ 'es'=>'Inversores que buscan rentabilidad por alquiler · Compradores de segunda residencia · Compradores de obra nueva o sobre plano · Particulares que diversifican su patrimonio con inmuebles','en'=>'Investors seeking rental yield · Second home buyers · New-build or off-plan buyers · Individuals diversifying their assets with real estate','fr'=>'Investisseurs à la recherche de rentabilité locative · Acheteurs de résidence secondaire · Acheteurs en construction neuve ou sur plan · Particuliers qui diversifient leur patrimoine avec l\'immobilier','de'=>'Investoren auf der Suche nach Mietrendite · Ferienwohnungskäufer · Käufer von Neubauten oder Projekten · Privatpersonen, die ihr Vermögen mit Immobilien diversifizieren','ru'=>'Инвесторы в поиске арендного дохода · Покупатели второго жилья · Покупатели новостроек и строящегося жилья · Частные лица, диверсифицирующие активы через недвижимость' ],
        'presup.b2.time'      => [ 'es'=>'Aproximadamente 4 minutos','en'=>'Approximately 4 minutes','fr'=>'Environ 4 minutes','de'=>'Etwa 4 Minuten','ru'=>'Примерно 4 минуты' ],
        'presup.b3.title'     => [ 'es'=>'Promotores y grandes proyectos','en'=>'Developers & Large Projects','fr'=>'Promoteurs et grands projets','de'=>'Projektentwickler & Großprojekte','ru'=>'Застройщики и крупные проекты' ],
        'presup.b3.sub'       => [ 'es'=>'Para operaciones de mayor escala, desarrollos o promociones en la zona.','en'=>'For larger-scale operations, developments or promotions in the area.','fr'=>'Pour des opérations de plus grande envergure, des développements ou des promotions dans la zone.','de'=>'Für größer angelegte Operationen, Entwicklungen oder Projekte in der Zone.','ru'=>'Для операций большего масштаба, застройки или продвижения в данном районе.' ],
        'presup.b3.desc'      => [ 'es'=>'Promotores inmobiliarios · Propietarios de terrenos que quieren construir · Grandes inversores con proyectos de desarrollo · Quien gestiona activos inmobiliarios de envergadura','en'=>'Real estate developers · Landowners who wish to build · Major investors with development projects · Those managing large-scale real estate assets','fr'=>'Promoteurs immobiliers · Propriétaires fonciers qui souhaitent construire · Grands investisseurs avec des projets de développement · Gestionnaires de grands actifs immobiliers','de'=>'Immobilienprojektentwickler · Grundstückseigentümer, die bauen möchten · Großinvestoren mit Entwicklungsprojekten · Verwalter umfangreicher Immobilienvermögen','ru'=>'Застройщики · Владельцы земельных участков, желающие строить · Крупные инвесторы с девелоперскими проектами · Управляющие крупными объектами недвижимости' ],
        'presup.b3.time'      => [ 'es'=>'Aproximadamente 5 minutos','en'=>'Approximately 5 minutes','fr'=>'Environ 5 minutes','de'=>'Etwa 5 Minuten','ru'=>'Примерно 5 минут' ],
        'presup.b4.title'     => [ 'es'=>'Empresas y profesionales','en'=>'Businesses & Professionals','fr'=>'Entreprises et professionnels','de'=>'Unternehmen & Fachleute','ru'=>'Компании и профессионалы' ],
        'presup.b4.sub'       => [ 'es'=>'Para negocios y profesionales que necesitan analizar una zona antes de actuar.','en'=>'For businesses and professionals who need to analyse an area before acting.','fr'=>'Pour les entreprises et les professionnels qui ont besoin d\'analyser une zone avant d\'agir.','de'=>'Für Unternehmen und Fachleute, die eine Zone vor dem Handeln analysieren müssen.','ru'=>'Для бизнеса и профессионалов, которым необходимо проанализировать район перед принятием решений.' ],
        'presup.b4.desc'      => [ 'es'=>'Empresas que abren una nueva sede · Departamentos de RRHH que reubican empleados · Pymes que buscan local o nave · Franquicias en expansión · Profesionales independientes que buscan ubicación para su actividad','en'=>'Companies opening a new headquarters · HR departments relocating employees · SMEs looking for premises or industrial space · Expanding franchises · Independent professionals looking for a location for their activity','fr'=>'Entreprises qui ouvrent un nouveau siège · Départements RH qui relocalisent des employés · PME à la recherche d\'un local ou d\'un entrepôt · Franchises en expansion · Professionnels indépendants à la recherche d\'un emplacement','de'=>'Unternehmen, die einen neuen Standort eröffnen · HR-Abteilungen, die Mitarbeiter versetzen · KMU auf der Suche nach Geschäftsräumen · Expandierende Franchises · Selbstständige auf der Suche nach einem Standort','ru'=>'Компании, открывающие новый офис · HR-отделы, переводящие сотрудников · МСП в поисках офиса или склада · Развивающиеся франшизы · Независимые профессионалы в поиске места для деятельности' ],
        'presup.b4.time'      => [ 'es'=>'Aproximadamente 5 minutos','en'=>'Approximately 5 minutes','fr'=>'Environ 5 minutes','de'=>'Etwa 5 Minuten','ru'=>'Примерно 5 минут' ],

