        // Descriptions (per page)
        'seo.desc.home'       => [ 'es'=>'Análisis territorial independiente en Alicante, Málaga y Marbella. Informes sobre seguridad, entorno y servicios antes de comprar, invertir o establecerse.','en'=>'Independent territorial analysis in Alicante, Málaga and Marbella. Reports on security, environment and services before buying, investing or settling.','fr'=>'Analyse territoriale indépendante à Alicante, Málaga et Marbella. Rapports sur la sécurité, l\'environnement et les services avant d\'acheter, d\'investir ou de s\'installer.','de'=>'Unabhängige Gebietsanalyse in Alicante, Málaga und Marbella. Berichte über Sicherheit, Umfeld und Dienstleistungen vor Kauf, Investition oder Niederlassung.','ru'=>'Независимый территориальный анализ в Аликанте, Малаге и Марбелье. Отчёты о безопасности, окружении и услугах перед покупкой, инвестициями или переездом.' ],
        'seo.desc.metodologia' => [ 'es'=>'Cómo trabajamos en ROMVILL: combinamos fuentes contrastadas y análisis sobre el terreno para ofrecerle información fiable sobre la zona.','en'=>'How we work at ROMVILL: we combine cross-checked sources and on-the-ground analysis to give you reliable information about the area.','fr'=>'Comment nous travaillons chez ROMVILL : nous combinons des sources recoupées et une analyse sur le terrain pour vous offrir des informations fiables sur la zone.','de'=>'Wie wir bei ROMVILL arbeiten: Wir kombinieren gegengeprüfte Quellen und Analysen vor Ort, um Ihnen verlässliche Informationen über die Zone zu bieten.','ru'=>'Как мы работаем в ROMVILL: мы сочетаем проверенные источники и анализ на месте, чтобы предоставить надёжную информацию о зоне.' ],
        'seo.desc.analisis'   => [ 'es'=>'Las dimensiones que analizamos de cada zona: seguridad, comunidad, sanidad y movilidad, con rigor profesional.','en'=>'The dimensions we analyse in each area: security, community, healthcare and mobility, with professional rigour.','fr'=>'Les dimensions que nous analysons dans chaque zone : sécurité, communauté, santé et mobilité, avec rigueur professionnelle.','de'=>'Die Dimensionen, die wir in jeder Zone analysieren: Sicherheit, Gemeinschaft, Gesundheit und Mobilität, mit professioneller Strenge.','ru'=>'Измерения, которые мы анализируем в каждой зоне: безопасность, сообщество, здравоохранение и мобильность, с профессиональной строгостью.' ],
        'seo.desc.sectores'   => [ 'es'=>'Análisis territorial para particulares, inversores, promotores y empresas que necesitan conocer una zona antes de decidir.','en'=>'Territorial analysis for individuals, investors, developers and businesses that need to know an area before deciding.','fr'=>'Analyse territoriale pour particuliers, investisseurs, promoteurs et entreprises qui ont besoin de connaître une zone avant de décider.','de'=>'Gebietsanalyse für Privatpersonen, Investoren, Projektentwickler und Unternehmen, die eine Zone vor der Entscheidung kennen müssen.','ru'=>'Территориальный анализ для частных лиц, инвесторов, девелоперов и компаний, которым нужно узнать зону перед принятием решения.' ],
        'seo.desc.contacto'   => [ 'es'=>'Solicite su informe de zona. Cuéntenos qué área le interesa y reciba un análisis independiente, sin compromiso.','en'=>'Request your area report. Tell us which area interests you and receive an independent analysis, with no obligation.','fr'=>'Demandez votre rapport de zone. Dites-nous quelle zone vous intéresse et recevez une analyse indépendante, sans engagement.','de'=>'Fordern Sie Ihren Gebietsbericht an. Sagen Sie uns, welche Zone Sie interessiert, und erhalten Sie eine unabhängige Analyse, unverbindlich.','ru'=>'Запросите отчёт по зоне. Расскажите, какая зона вас интересует, и получите независимый анализ без обязательств.' ],
        'seo.desc.perfil-seguridad'   => [ 'es'=>'Analizamos el contexto de seguridad de la zona combinando información contrastada y observación sobre el terreno.','en'=>'We analyse the security context of the area by combining cross-checked information and on-the-ground observation.','fr'=>'Nous analysons le contexte de sécurité de la zone en combinant des informations recoupées et l\'observation sur le terrain.','de'=>'Wir analysieren den Sicherheitskontext der Zone durch die Kombination gegengeprüfter Informationen und Beobachtung vor Ort.','ru'=>'Мы анализируем контекст безопасности зоны, сочетая проверенную информацию и наблюдение на месте.' ],
        'seo.desc.perfil-demografico' => [ 'es'=>'Le mostramos cómo es la comunidad de la zona: composición, ambiente y evolución del entorno.','en'=>'We show you what the community of the area is like: composition, atmosphere and evolution of the environment.','fr'=>'Nous vous montrons comment est la communauté de la zone : composition, ambiance et évolution de l\'environnement.','de'=>'Wir zeigen Ihnen, wie die Gemeinschaft der Zone ist: Zusammensetzung, Atmosphäre und Entwicklung des Umfelds.','ru'=>'Мы показываем, какова община зоны: состав, атмосфера и развитие окружения.' ],
        'seo.desc.perfil-sanidad'     => [ 'es'=>'Analizamos la infraestructura sanitaria accesible desde la zona: hospitales, centros de salud, farmacias y urgencias.','en'=>'We analyse the healthcare infrastructure accessible from the area: hospitals, health centres, pharmacies and emergency services.','fr'=>'Nous analysons l\'infrastructure sanitaire accessible depuis la zone : hôpitaux, centres de santé, pharmacies et urgences.','de'=>'Wir analysieren die von der Zone aus zugängliche Gesundheitsinfrastruktur: Krankenhäuser, Gesundheitszentren, Apotheken und Notdienste.','ru'=>'Мы анализируем доступную из зоны медицинскую инфраструктуру: больницы, медицинские центры, аптеки и неотложную помощь.' ],
        'seo.desc.perfil-movilidad'   => [ 'es'=>'Estudiamos cómo se mueve la zona: accesos, transporte público, aparcamiento y tiempos de desplazamiento.','en'=>'We study how the area moves: access roads, public transport, parking and travel times.','fr'=>'Nous étudions comment se déplace la zone : accès, transports publics, stationnement et temps de trajet.','de'=>'Wir untersuchen, wie sich die Zone bewegt: Zufahrten, öffentlicher Verkehr, Parken und Reisezeiten.','ru'=>'Мы изучаем, как движется зона: подъезды, общественный транспорт, парковку и время в пути.' ],
        'seo.desc.perfil-proyeccion'  => [ 'es'=>'Planificación pública y proyección futura de la zona. Proyectos urbanísticos, infraestructuras y normativa del suelo.','en'=>'Public planning and the area\'s future outlook. Urban development projects, infrastructure and land-use regulations.','fr'=>'Planification publique et projection future de la zone. Projets d\'urbanisme, infrastructures et réglementation des sols.','de'=>'Öffentliche Planung und Zukunftsausblick des Gebiets. Städtebauprojekte, Infrastruktur und Bodennutzungsvorschriften.','ru'=>'Государственное планирование и перспективы развития зоны. Градостроительные проекты, инфраструктура и нормы землепользования.' ],
